a5ce6b2c-19bd-4b70-93b8-b1bf92850fb6.description:
\documentclass{article}
\begin{document}

  A \emph{topology} on a set $X$ is a collection $\mathcal{T}$ of subsets of $X$ having the following properties:
  \begin{enumerate}
      \item $\varnothing$ and $X$ are in $\mathcal{T}$.
      \item The union of the elements of any subcollection of $\mathcal{T}$ is in $\mathcal{T}$.
      \item The intersection of the elements of any finite subcollection of $\mathcal{T}$ is in $\mathcal{T}$.
  \end{enumerate}
  A set $X$ for which a topology $\mathcal{T}$ has been specified is called a \emph{topological space}.

  Properly speaking, a topological space is an ordered pair $(X,\mathcal{T})$ consisting of a set $X$ and a topology $\mathcal{T}$ on $X$, but we often omit specific mention of $\mathcal{T}$ if no confusion will arise.

  If $X$ is a topological space with topology $\mathcal{T}$, we say that a subset $U$ of $X$ is an \emph{open set} of $X$ if $U$ belongs to the collection $\mathcal{T}$. Using this terminology, one can say that a topological space is a set $X$ together with a collection of subsets of $X$, called \emph{open sets}, such that $\varnothing$ and $X$ are both open, and such that arbitrary unions and finite intersections of open sets are open.

\end{document}

354296d9-1507-4b03-974d-91e93889d6c8.description:
\documentclass{article}
\begin{document}

  Suppose that $\mathcal{T}$ and $\mathcal{T}'$ are two topologies on a given set $X$. If $\mathcal{T}' \supset \mathcal{T}$, we say that $\mathcal{T}'$ is \emph{finer} than $\mathcal{T}$; if $\mathcal{T}'$ properly contains $\mathcal{T}$, we say that $\mathcal{T}'$ is \emph{strictly finer} than $\mathcal{T}$. We also say that $\mathcal{T}$ is \emph{coarser} than $\mathcal{T}'$, or \emph{strictly coarser}, in these two respective situations. We say that $\mathcal{T}$ is \emph{comparable} with $\mathcal{T}'$ if either $\mathcal{T}' \supset \mathcal{T}$ or $\mathcal{T} \supset \mathcal{T}'$.

\end{document}

db56a83e-27bb-4963-93f3-b7a0f6037c2c.description:
\documentclass{article}
\begin{document}

  If $X$ is a set, a \emph{basis} for a \nodelink{topology}{topology} on $X$ is a collection $\mathcal{B}$ of subsets of $X$ (called \emph{basis elements}) such that
  \begin{enumerate}
      \item For each $x \in X$, there is at least one basis element
            $B \in \mathcal{B}$ containing $x$.
      \item If $x$ belongs to the intersection of two basis elements
            $B_1,B_2 \in \mathcal{B}$, then there is a basis element
            $B_3 \in \mathcal{B}$ containing $x$ such that
            $B_3 \subset B_1 \cap B_2$.
  \end{enumerate}
  If $\mathcal{B}$ satisfies these two conditions, then we define the \emph{topology} $\mathcal{T}$ \emph{generated by} $\mathcal{B}$ as follows: a subset $U$ of $X$ is said to be open in $X$ (that is, to be an element of $\mathcal{T}$) if for each $x \in U$ there is a basis element $B \in \mathcal{B}$ such that $x \in B$ and $B \subset U$. Note that each basis element is itself an element of $\mathcal{T}$.

\end{document}

bf2d886a-6f02-4dff-9f9b-9e9cf850d116.description:
\documentclass{article}
\begin{document}

  If $\mathcal{B}$ is the collection of all open intervals in the real line,
  \[
    (a,b) = \{\, x \mid a < x < b \,\},
  \]
  the \nodelink{topology}{topology} generated by the \nodelink{basis}{basis} $\mathcal{B}$ is called the \emph{standard topology} on the real line. Whenever we consider $\mathbb{R}$, we shall suppose it is given this topology unless we specifically state otherwise.

\end{document}

12d6b1de-6aa9-4888-8a9a-be775bb9ba7a.description:
\documentclass{article}
\begin{document}

  A \emph{subbasis} $\mathcal{S}$ for a \nodelink{topology}{topology} on a set $X$ is a collection of subsets of $X$ whose union equals $X$. The \emph{topology generated by the subbasis} $\mathcal{S}$ is defined to be the collection $\mathcal{T}$ of all unions of finite intersections of elements of $\mathcal{S}$.

\end{document}

90e62c58-aaa4-435c-bf67-4ce2c07864ee.description:
\documentclass{article}
\begin{document}

  Let $X$ be a set with a simple order relation, and assume $X$ has more than one element. Let $\mathcal{B}$ be the collection of all sets of the following types:
  \begin{enumerate}
    \item All open intervals $(a,b)$ in $X$.
    \item All intervals of the form $[a_0,b)$, where $a_0$ is the smallest element (if any) of $X$.
    \item All intervals of the form $(a,b_0]$, where $b_0$ is the largest element (if any) of $X$.
  \end{enumerate}
  The collection $\mathcal{B}$ is a \nodelink{basis}{basis} for a \nodelink{topology}{topology} on $X$, which is called the \emph{order topology}.

\end{document}

989c632f-cb55-436d-b070-9c7c93e52b28.description:
\documentclass{article}
\begin{document}

  Let $X$ and $Y$ be topological spaces. The \emph{product topology} on $X \times Y$ is the \nodelink{topology}{topology} having as \nodelink{basis}{basis} the collection $\mathcal{B}$ of all sets of the form $U \times V$, where $U$ is an open subset of $X$ and $V$ is an open subset of $Y$.

\end{document}

12539c62-adbb-4edb-bb87-a3afd875e581.description:
\documentclass{article}
\begin{document}

  Let $X$ be a \nodelink{topological space}{topological space} with topology $\mathcal{T}$. If $Y$ is a subset of $X$, the collection
  \[
    \mathcal{T}_{Y} = \{\, Y \cap U \mid U \in \mathcal{T} \,\}
  \]
  is a topology on $Y$, called the \emph{subspace topology}. With this topology, $Y$ is called a \emph{subspace} of $X$; its open sets consist of all intersections of open sets of $X$ with $Y$.

  If $Y$ is a subspace of $X$, we say that a set $U$ is \emph{open in $Y$} (or \emph{open relative to $Y$}) if it belongs to the topology of $Y$; this implies in particular that it is a subset of $Y$. We say that $U$ is \emph{open in $X$} if it belongs to the topology of $X$.

\end{document}

eed3342b-a8ff-4a72-9d55-f55ef131103d.description:
\documentclass{article}
\begin{document}

  A subset $A$ of a \nodelink{topological space}{topological space} $X$ is said to be \emph{closed} if the set $X - A$ is open.

\end{document}

9d11245e-d203-438a-ba09-ab9f17de9a2a.description:
\documentclass{article}
\begin{document}

  Given a subset $A$ of a \nodelink{topological space}{topological space} $X$, the \emph{interior} of $A$ is defined as the union of all open sets contained in $A$. The interior of $A$ is denoted as Int$A$.

\end{document}

9b080105-461e-4166-8ebe-69985782c17f.description:
\documentclass{article}
\begin{document}

  Given a subset $A$ of a \nodelink{topological space}{topological space} $X$, the \emph{closure} of $A$ is defined as the intersection of all \nodelink{closed}{closed} sets contained in $A$. The closure of $A$ is denoted by $\bar{A}$.

\end{document}

fda4ec8f-6682-40b0-8db8-3e83673e6547.description:
\documentclass{article}
\begin{document}

  If $A$ is a subset of the \nodelink{topological space}{topological space} $X$ and if $x$ is a point of $X$, we say that $x$ is a \emph{limit point} (or \emph{cluster point}, or \emph{point of accumulation}) of $A$ if every neighborhood of $x$ intersects $A$ in some point \emph{other than $x$ itself}. Said differently, $x$ is a limit point of $A$ if it belongs to the \nodelink{closure}{closure} of $A - \{x\}$. The point $x$ may lie in $A$ or not; for this definition it does not matter.

\end{document}

4fa02319-da5c-48e5-902e-0cce440b97c9.description:
\documentclass{article}
\begin{document}

  A \nodelink{topological space}{topological space} $X$ is called a \emph{Hausdorff space} if for each pair $x_{1}, x_{2}$ of distinct points of $X$, there exist neighborhoods $U_{1}$ and $U_{2}$ of $x_{1}$ and $x_{2}$, respectively, that are disjoint.

\end{document}

8683e9b9-d53c-4704-8b36-83091f166a61.description:
\documentclass{article}
\begin{document}

  Let $X$ and $Y$ be \nodelink{topological spaces}{topological spaces}. A function $f : X \to Y$ is said to be \emph{continuous} if for each open subset $V$ of $Y$, the set $f^{-1}(V)$ is an open subset of $X$.

  Recall that $f^{-1}(V)$ is the set of all points $x$ of $X$ for which $f(x) \in V$; it is empty if $V$ does not intersect the image set $f(X)$ of $f$.

  Continuity of a function depends not only upon the function $f$ itself, but also on the topologies specified for its domain and range. If we wish to emphasize this fact, we can say that $f$ is continuous \emph{relative} to specific topologies on $X$ and $Y$.

\end{document}

6e992efa-f76f-45a1-9f25-d8f25d0d2f1d.description:
\documentclass{article}
\begin{document}

  Let $X$ and $Y$ be \nodelink{topological spaces}{topological spaces}, and let $f : X \to Y$ be a bijection. If both the function $f$ and the inverse function
  \[
    f^{-1} : Y \to X
  \]
  are \nodelink{continuous}{continuous}, then $f$ is called a \emph{homeomorphism}.

  The condition that $f^{-1}$ be continuous says that for each open set $U \subset X$, the inverse image of $U$ under the map $f^{-1} : Y \to X$ is open in $Y$. But the inverse image of $U$ under $f^{-1}$ is the same as the image of $U$ under the map $f$. Thus, another way to define a homeomorphism is to say that it is a bijective correspondence $f : X \to Y$ such that $f(U)$ is open if and only if $U$ is open.

\end{document}

100af981-6e78-411f-9c6a-4a64760437d2.description:
\documentclass{article}
\begin{document}

  Suppose that $f : X \to Y$ is an injective \nodelink{continuous}{continuous} map, where $X$ and $Y$ are \nodelink{topological spaces}{topological spaces}. Let $Z$ be the image set $f(X)$, considered as a \nodelink{subspace}{subspace} of $Y$; then the function $f' : X \to Z$ obtained by restricting the range of $f$ is bijective. If $f'$ happens to be a \nodelink{homeomorphism}{homeomorphism} of $X$ with $Z$, we say that the map $f : X \to Y$ is a \emph{topological embedding}, or simply an \emph{embedding}, of $X$ in $Y$.

\end{document}

4461a359-f997-45a1-8edd-8e59f2c4c049.description:
\documentclass{article}
\begin{document}

  A \emph{metric} on a set $X$ is a function
  \[
    d : X \times X \longrightarrow \mathbb{R}
  \]
  having the following properties:
  \begin{enumerate}
    \item $d(x,y) \ge 0$ for all $x,y \in X$; equality holds if and only if $x = y$.
    \item $d(x,y) = d(y,x)$ for all $x,y \in X$.
    \item (Triangle inequality) $d(x,y) + d(y,z) \ge d(x,z)$ for all $x,y,z \in X$.
  \end{enumerate}

  Given a metric $d$ on $X$, the number $d(x,y)$ is often called the \emph{distance} between $x$ and $y$ in the metric $d$. Given $\varepsilon > 0$, consider the set
  \[
    B_{d}(x,\varepsilon) = \{\, y \mid d(x,y) < \varepsilon \,\}
  \]
  of all points $y$ whose distance from $x$ is less than $\varepsilon$. It is called the \emph{$\varepsilon$-ball centered at $x$}. Sometimes we omit the metric $d$ from the notation and write this ball simply as $B(x,\varepsilon)$ when no confusion will arise.

\end{document}

151a9fe1-2423-4ee1-afd5-2527527913cc.description:
\documentclass{article}
\begin{document}

  If $d$ is a \nodelink{metric}{metric} on the set $X$, then the collection of all $\varepsilon$-balls $B_{d}(x,\varepsilon)$, for $x \in X$ and $\varepsilon > 0$, is a \nodelink{basis}{basis} for a \nodelink{topology}{topology} on $X$, called the \emph{metric topology} induced by $d$.

\end{document}

8cb13a09-6795-4ffe-9031-7b374611413e.description:
\documentclass{article}
\begin{document}

  If $X$ is a \nodelink{topological space}{topological space}, $X$ is said to be \emph{metrizable} if there exists a \nodelink{metric}{metric} $d$ on the set $X$ that induces the topology of $X$. A \emph{metric space} is a metrizable space $X$ together with a specific metric $d$ that gives the topology of $X$.

\end{document}

09bf030c-3faa-4f32-a226-6b506db7cd30.description:
\documentclass{article}
\begin{document}

  Given an index set $J$, and given points $x = (x_{\alpha})_{\alpha \in J}$ and $y = (y_{\alpha})_{\alpha \in J}$ of $\mathbb{R}^{J}$, let us define a \nodelink{metric}{metric} $\bar{\rho}$ on $\mathbb{R}^{J}$ by the equation
  \[
    \bar{\rho}(x,y) = \sup \{\, \bar{d}(x_{\alpha}, y_{\alpha}) \mid \alpha \in J \,\},
  \]
  where $\bar{d}$ is the standard \nodelink{bounded}{bounded} metric on $\mathbb{R}$. It is easy to check that $\bar{\rho}$ is indeed a metric; it is called the \emph{uniform metric} on $\mathbb{R}^{J}$, and the \nodelink{topology}{topology} it induces is called the \emph{uniform topology}.

\end{document}

51b3392e-caba-4edd-9c4c-ec4dcd23eb8d.description:
\documentclass{article}
\begin{document}

  Let $f_{n} : X \to Y$ be a sequence of functions from the set $X$ to the \nodelink{metric space}{metric space} $Y$. Let $d$ be the \nodelink{metric}{metric} on $Y$. We say that the sequence $(f_{n})$ \emph{converges uniformly} to the function $f : X \to Y$ if, given $\varepsilon > 0$, there exists an integer $N$ such that
  \[
    d\bigl(f_{n}(x),\, f(x)\bigr) < \varepsilon
  \]
  for all $n > N$ and all $x \in X$.

\end{document}

b2a5c91d-a532-4442-a3a3-2b6b5c015b5f.description:
\documentclass{article}
\begin{document}

  Let $X$ be a \nodelink{topological space}{topological space}. A \emph{separation} of $X$ is a pair $U, V$ of disjoint nonempty open subsets of $X$ whose union is $X$. The space $X$ is said to be \emph{connected} if there does not exist a separation of $X$.

  Connectedness is a topological property, since it is formulated entirely in terms of the collection of open sets of $X$. Said differently, if $X$ is connected, so is any space \nodelink{homeomorphic}{homeomorphic} to $X$.

  Another way of formulating the definition of connectedness is the following:
  \begin{quote}
  A space $X$ is connected if and only if the only subsets of $X$ that are both open \emph{and} \nodelink{closed}{closed} in $X$ are the empty set and $X$ itself.
  \end{quote}

\end{document}

48373451-4152-4a58-9db1-3ff0e38fb787.description:
\documentclass{article}
\begin{document}

  Given points $x$ and $y$ of the \nodelink{space}{space} $X$, a \emph{path} in $X$ from $x$ to $y$ is a \nodelink{continuous}{continuous} map $f : [a,b] \to X$ of some \nodelink{closed}{closed} interval in the real line into $X$, such that $f(a) = x$ and $f(b) = y$. A space $X$ is said to be \emph{path connected} if every pair of points of $X$ can be joined by a path in $X$.

\end{document}

157217ba-b862-4af5-9152-0ce7c1f49d89.description:
\documentclass{article}
\begin{document}

  Given a \nodelink{topological space}{topological space} $X$, define an equivalence relation on $X$ by setting $x \sim y$ if there is a connected \nodelink{subspace}{subspace} of $X$ containing both $x$ and $y$. The equivalence classes are called the \emph{components} (or the \emph{connected components}) of $X$.

\end{document}

f9a700e1-77b3-45e0-98ab-6188f4733c36.description:
\documentclass{article}
\begin{document}

  We define an equivalence relation on the \nodelink{space}{space} $X$ by defining $x \sim y$ if there is a \nodelink{path}{path} in $X$ from $x$ to $y$. The equivalence classes are called the \emph{path components} of $X$.

\end{document}

005899c2-0525-4ebe-af88-a2d4b98838fe.description:
\documentclass{article}
\begin{document}

  A \nodelink{space}{space} $X$ is said to be \emph{locally connected at $x$} if for every neighborhood $U$ of $x$, there is a connected neighborhood $V$ of $x$ contained in $U$. If $X$ is locally connected at each of its points, it is said simply to be \emph{locally connected}.

\end{document}

02620a36-01aa-4593-a2df-72cd4fd5c39b.description:
\documentclass{article}
\begin{document}

  A \nodelink{space}{space} $X$ is said to be \emph{locally path connected at $x$} if for every neighborhood $U$ of $x$, there is a \nodelink{path}{path}-connected neighborhood $V$ of $x$ contained in $U$. If $X$ is locally path connected at each of its points, then it is said to be \emph{locally path connected}.

\end{document}

4f65cd04-0f52-4f24-a823-3dbb0c3e58a3.description:
\documentclass{article}
\begin{document}

  A collection $\mathcal{A}$ of subsets of a \nodelink{space}{space} $X$ is said to \emph{cover} $X$, or to be a \emph{covering} of $X$, if the union of the elements of $\mathcal{A}$ is equal to $X$. It is called an \emph{open covering} of $X$ if its elements are open subsets of $X$.

\end{document}

1797b419-4509-4e84-9177-0af931fbb7e8.description:
\documentclass{article}
\begin{document}

  A \nodelink{space}{space} $X$ is said to be \emph{compact} if every \nodelink{open covering}{open covering} $\mathcal{A}$ of $X$ contains a finite subcollection that also covers $X$.

\end{document}

e9e374a1-d9b8-475a-8575-a23874a54e01.description:
\documentclass{article}
\begin{document}

  A function $f$ from the \nodelink{metric space}{metric space} $(X, d_{X})$ to the metric space $(Y, d_{Y})$ is said to be \emph{uniformly continuous} if, given
$\varepsilon > 0$, there is a $\delta > 0$ such that for every pair of points $x_{0}, x_{1}$ of $X$,
  \[
    d_{X}(x_{0}, x_{1}) < \delta \Longrightarrow d_{Y}\bigl(f(x_{0}), f(x_{1})\bigr) < \varepsilon.
  \]

\end{document}

a41257ae-398c-4b1d-9c06-b88f1838a9b5.description:
\documentclass{article}
\begin{document}

  If $X$ is a \nodelink{space}{space}, a point $x$ of $X$ is said to be an \emph{isolated point} of $X$ if the one-point set $\{x\}$ is open in $X$.

\end{document}

dd6ac54c-4cf6-400c-bf8d-b16776b120dd.description:
\documentclass{article}
\begin{document}

  A \nodelink{space}{space} $X$ is said to be \emph{limit point compact} if every infinite subset of $X$ has a \nodelink{limit point}{limit point}.

\end{document}

4cbeabda-6b29-43e3-8e73-6c65003ff77c.description:
\documentclass{article}
\begin{document}

  Let $X$ be a \nodelink{topological space}{topological space}. If $(x_{n})$ is a sequence of points of $X$, and if
  \[
    n_{1} < n_{2} < \cdots < n_{i} < \cdots
  \]
  is an increasing sequence of positive integers, then the sequence $(y_{i})$ defined by setting $y_{i} = x_{n_{i}}$ is called a \emph{subsequence} of the sequence $(x_{n})$. The space $X$ is said to be \emph{sequentially compact} if every sequence of points of $X$ has a convergent subsequence.

\end{document}

11121fd1-df61-4129-8fab-5c164af3ac24.description:
\documentclass{article}
\begin{document}

  A \nodelink{space}{space} $X$ is said to be \emph{locally compact at $x$} if there is some \nodelink{compact}{compact} \nodelink{subspace}{subspace} $C$ of $X$ that contains a neighborhood of $x$. If $X$ is locally compact at each of its points, $X$ is said simply to be \emph{locally compact}.

\end{document}

5f9c9834-db1b-4b4e-9673-7f34f54aa88d.description:
\documentclass{article}
\begin{document}

  If $Y$ is a \nodelink{compact}{compact} \nodelink{hausdorff space}{Hausdorff space} and $X$ is a proper \nodelink{subspace}{subspace} of $Y$ whose \nodelink{closure}{closure} equals $Y$, then $Y$ is said to be a \emph{compactification} of $X$. If $Y - X$ equals a single point, then $Y$ is called the \emph{one-point compactification} of $X$.

\end{document}

0d38576f-8782-4a4a-b152-0ee236cf672f.description:
\documentclass{article}
\begin{document}

  A \nodelink{space}{space} $X$ is said to have a \emph{countable basis at $x$} if there is a countable collection $\mathcal{B}$ of neighborhoods of $x$ such that each neighborhood of $x$ contains at least one of the elements of $\mathcal{B}$. A space that has a countable \nodelink{basis}{basis} at each of its points is said to satisfy the \emph{first countability axiom}, or to be \emph{first-countable}.

\end{document}

e92b873d-6669-451f-9c29-f3874ae61e8a.description:
\documentclass{article}
\begin{document}

  If a \nodelink{space}{space} $X$ has a \nodelink{countable basis}{countable basis} for its topology, then $X$ is said to satisfy the \emph{second countability axiom}, or to be \emph{second-countable}.

\end{document}

641984a2-25e2-48b6-80f8-16d0c86af516.description:
\documentclass{article}
\begin{document}

  A subset $A$ of a \nodelink{space}{space} $X$ is said to be \emph{dense} in $X$ if the \nodelink{closure}{closure} $\overline{A} = X$.

\end{document}

181c2330-5caf-4eed-ae0b-508d50001f06.description:
\documentclass{article}
\begin{document}

  Suppose that one-point sets are \nodelink{closed}{closed} in a \nodelink{space}{space} $X$. Then $X$ is said to be \emph{regular} if for each pair consisting of a point $x$ and a closed set $B$ disjoint from $x$, there exist disjoint open sets containing $x$ and $B$, respectively.

\end{document}

c69f9692-d023-4215-af78-15686d41dbda.description:
\documentclass{article}
\begin{document}

  Suppose that one-point sets are \nodelink{closed}{closed} in $X$. The \nodelink{space}{space} $X$ is said to be \emph{normal} if for each pair $A, B$ of disjoint closed sets of $X$, there exist disjoint open sets containing $A$ and $B$, respectively.

\end{document}
